// Get all rows from the sheet
const rows = $input.all();
const query = $('Execute Workflow Trigger').first().json.query || '';

// Build the knowledge base content
const knowledge = rows.map(r => r.json);

// Format as readable text
let result = 'JAYDEN MIKUS — KNOWLEDGE BASE\n';
result += '================================\n\n';

// Group by category
const byCategory = {};
for (const row of knowledge) {
  const cat = row.Category || 'General';
  if (!byCategory[cat]) byCategory[cat] = [];
  byCategory[cat].push(`${row.Topic}: ${row.Content}`);
}

for (const [cat, items] of Object.entries(byCategory)) {
  result += `## ${cat}\n`;
  result += items.join('\n');
  result += '\n\n';
}

// Try to find rows relevant to the query
const queryLower = query.toLowerCase();
const relevant = knowledge.filter(row => {
  const text = `${row.Category} ${row.Topic} ${row.Content}`.toLowerCase();
  const keywords = queryLower.split(' ').filter(w => w.length > 2);
  return keywords.some(kw => text.includes(kw));
});

if (relevant.length > 0) {
  result += '\n## MOST RELEVANT FOR THIS QUERY\n';
  result += relevant.map(r => `${r.Topic}: ${r.Content}`).join('\n');
}

return [{ json: { knowledge: result, rowCount: knowledge.length } }];
